{
  "type": "DRAG_FILL",
  "lessonText": "Engage in a gamified challenge to reinforce your understanding of game development concepts.",
  "data": {
    "challenges": [
      {
        "instruction": "Fill in the blanks to complete the game loop.",
        "codeTemplate": "while ___: \n    ___() \n    ___()",
        "options": ["running", "update", "render"],
        "correctAnswer": "running,update,render",
        "explanation": "The game loop continues while the game is running, updating game states, and rendering the graphics."
      },
      {
        "instruction": "Complete the function to initialize a game.",
        "codeTemplate": "def ___(): \n    ___('Game Title') \n    ___()",
        "options": ["initialize_game", "set_title", "load_assets"],
        "correctAnswer": "initialize_game,set_title,load_assets",
        "explanation": "The function initializes the game by setting the title and loading necessary assets."
      },
      {
        "instruction": "Identify the correct sequence for handling user input.",
        "codeTemplate": "def handle_input(): \n    ___() \n    ___() \n    ___()",
        "options": ["get_input", "process_input", "update_state"],
        "correctAnswer": "get_input,process_input,update_state",
        "explanation": "Handling user input involves getting the input, processing it, and updating the game state accordingly."
      },
      {
        "instruction": "Complete the rendering function.",
        "codeTemplate": "def render(): \n    ___() \n    ___() \n    ___()",
        "options": ["clear_screen", "draw_objects", "display_score"],
        "correctAnswer": "clear_screen,draw_objects,display_score",
        "explanation": "The rendering function clears the screen, draws game objects, and displays the score."
      }
    ]
  }
}
